using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;

namespace ConstExpr.Benchmarks.MathTests;

/// <summary>
/// Compares Math.Acos against the FastAcos approximations generated by AcosFunctionOptimizer.
///
/// Two type groups are benchmarked independently:
///   Float  – MathF.Acos  vs FastAcos(float)   (max error ≈ 1.7e-5 rad, Abramowitz &amp; Stegun)
///   Double – Math.Acos   vs FastAcos(double)   (max error ≈ 1.8e-8 rad, Taylor series)
///
/// GroupBenchmarksBy(ByCategory) gives each group its own Baseline ratio column so
/// float and double results are not compared against each other.
///
/// Run command:
///   dotnet run -c Release --project ConstExpr.Benchmarks/ConstExpr.Benchmarks.csproj --filter '*AcosBenchmark*'
/// </summary>
[MemoryDiagnoser]
[DisassemblyDiagnoser(maxDepth: 3, printSource: true)]
[GroupBenchmarksBy(BenchmarkLogicalGroupRule.ByCategory)]
[CategoriesColumn]
public class AcosBenchmark
{
    // 1 024 values uniformly distributed over the Acos domain [-1, 1].
    // Instance fields populated at runtime so the JIT cannot constant-fold.
    private const int N = 1_024;
    private float[]  _floatData  = null!;
    private double[] _doubleData = null!;

    [GlobalSetup]
    public void Setup()
    {
        var rng = new Random(42);
        _floatData  = new float[N];
        _doubleData = new double[N];
        for (var i = 0; i < N; i++)
        {
            var v = rng.NextDouble() * 2.0 - 1.0; // uniform in [-1, 1]
            _floatData[i]  = (float)v;
            _doubleData[i] = v;
        }
    }

    // ── float ──────────────────────────────────────────────────────────────

    /// <summary>Built-in MathF.Acos — hardware-accurate, full-precision float result.</summary>
    [Benchmark(Baseline = true, OperationsPerInvoke = N)]
    [BenchmarkCategory("Float")]
    public float DotNetAcos_Float()
    {
        var sum = 0f;
        foreach (var v in _floatData)
            sum += MathF.Acos(v);
        return sum;
    }

    /// <summary>
    /// FastAcos(float) — generated by AcosFunctionOptimizer.
    /// Minimax polynomial (Abramowitz &amp; Stegun §4.4.45).
    /// Max absolute error ≈ 1.7e-5 rad.
    /// </summary>
    [Benchmark(OperationsPerInvoke = N)]
    [BenchmarkCategory("Float")]
    public float FastAcos_Float()
    {
        var sum = 0f;
        foreach (var v in _floatData)
            sum += FastAcosFloat(v);
        return sum;
    }

    // ── double ─────────────────────────────────────────────────────────────

    /// <summary>Built-in Math.Acos — hardware-accurate, full-precision double result.</summary>
    [Benchmark(Baseline = true, OperationsPerInvoke = N)]
    [BenchmarkCategory("Double")]
    public double DotNetAcos_Double()
    {
        var sum = 0.0;
        foreach (var v in _doubleData)
            sum += Math.Acos(v);
        return sum;
    }

    /// <summary>
    /// FastAcos(double) — generated by AcosFunctionOptimizer.
    /// Horner-evaluated Taylor series for asin(t)/t, split at x = 0.5.
    /// Max absolute error ≈ 1.8e-8 rad.
    /// </summary>
    [Benchmark(OperationsPerInvoke = N)]
    [BenchmarkCategory("Double")]
    public double FastAcos_Double()
    {
        var sum = 0.0;
        foreach (var v in _doubleData)
            sum += FastAcosDouble(v);
        return sum;
    }

    // ── implementations (mirror of AcosFunctionOptimizer generated code) ───

    private static float FastAcosFloat(float x)
    {
        var negative = x < 0f;
        x = Single.Abs(x);

        // Minimax polynomial: approximates acos(x) / sqrt(1-x) on [0, 1]
        // Coefficients: Abramowitz & Stegun table 4.4.45
        var p = Single.FusedMultiplyAdd(-0.0187293f, x, 0.0742610f);
        p = Single.FusedMultiplyAdd(p, x, -0.2121144f);
        p = Single.FusedMultiplyAdd(p, x,  1.5707288f);
        p *= Single.Sqrt(1f - x);

        // Exploit symmetry: acos(-x) = π - acos(x)
        return negative ? Single.Pi - p : p;
    }

    private static double FastAcosDouble(double x)
    {
        var negative = x < 0.0;
        x = Double.Abs(x);
        var big = x > 0.5;

        // Choose t such that u = t² ≤ 0.25 in both branches
        var t = big ? Double.Sqrt((1.0 - x) * 0.5) : x;
        var u = t * t;

        // Horner evaluation of asin(t)/t via Taylor series:
        // asin(t)/t = Σ C_n·u^n,  C_n = (2n-1)!! / ((2n)!! · (2n+1))
        var p = Double.FusedMultiplyAdd(u, 2027025.0 / 175472640.0,  // n=8
                                            135135.0 /   9676800.0); // n=7
        p = Double.FusedMultiplyAdd(u, p, 10395.0 / 599040.0); // n=6
        p = Double.FusedMultiplyAdd(u, p,   945.0 /  42240.0); // n=5
        p = Double.FusedMultiplyAdd(u, p,   105.0 /   3456.0); // n=4
        p = Double.FusedMultiplyAdd(u, p,    15.0 /    336.0); // n=3
        p = Double.FusedMultiplyAdd(u, p,     3.0 /     40.0); // n=2
        p = Double.FusedMultiplyAdd(u, p,     1.0 /      6.0); // n=1
        p = Double.FusedMultiplyAdd(u, p,     1.0);             // n=0

        var asinT  = t * p;
        var result = big ? 2.0 * asinT : Math.PI / 2.0 - asinT;

        return negative ? Math.PI - result : result;
    }
}

